    var _addr = std.Io.net.IpAddress{ .ip4 = .{ .bytes = .{ 0, 0, 0, 0 }, .port = port } };
    var _srv = std.Io.net.listen(&_addr, _io, .{}) catch |e| {
        std.debug.print("Http.serve: cannot bind port {d}: {s}\n", .{ port, @errorName(e) });
        return;
    };
